  o.age=age;
  o.job=job;
  o.sayName=function(){
    alert(this.name);
  };
  return o;   //将创建的对象返回
}
var person=createPerson("Jim",22,"Doctor");
```
缺点：工厂模式虽然解决了创建多个相似对象的问题，但却没有解决对象识别的问题（怎样知道一个对象的类型）。


2. 构造函数模式
```js
function Person(name,age,job){
  this.name=name;
  this.age=age;
  this.job=job;
  this.sayName=function(){
    alert(this.name);
  }
}
var person=new Person("Jim",22,"Doctor");
```

构造函数模式相对于工厂模式有几个显著的区别
（1） 没有显式地创建对象
（2）直接将属性和方法赋给了this对象
（3）没有return语句
（4）函数名的首字母大写（Person和createPerson）：按照惯例，构造函数始终都是以大写字母开头，而非构造函数则应该以小写字母开头

缺点：ECMAScript中的函数是对象，因此每定义一个函数，也就是实例化了一个对象。而构造函数在每次创建的时候都会完成同样任务的function实例(sayName)，这是很没有必要的。因此可以把函数定义转移到构造函数外部来解决这个问题。


3. 原型模式
```js
function Person(){}
Person.prototype.name="Jim";
Person.prototype.age=22;
Person.protoType.job="Doctor";
Person.protoType.sayName=function(){
  alert(this.name);
}
var person=new Person();
person.sayName();   //Jim
```
#可以让所有对象实例共享它所包含的属性和方法。
原型语法简单写法：
```js
function Person(){}
Person.prototype={
  constructor:Person,
  name:"Jim",
  age:22,
  job:"Doctor",
  sayName:function(){
    alert(this.name);
  }
}
```
缺点：“共享”性，即当没有对Person的friends赋值时，直接调用原型属性并修改，就会直接导致原型修改。
```js
function Person(){}
Person.prototype={
  friends:["Amy","Sam"],
};
var person1=new Person();
var person2=new Person();
person1.friends.push("Van");
alert(person1.friends);     //"Amy,Sam,Van"
alert(person2.friends);     //"Amy,Sam,Van"
```

总结：
（1）工厂模式：在函数里面创建对象，并添加属性和方法。但没有解决对象识别问题，最后被构造函数模式所取代。
（2）构造函数模式：可以像创建内置对象实例一样使用new操作符。但没函数不局限于任何对象，因此没有了封装性。
（3）原型模式：使用构造函数的prototype属性指定应该共享的属性和方法。但单独使用原型模式的话，就会使不需要共享的属性和方法被共享
### 构造函数模式用于定义实例属性，而原型模式用于定义方法和共享属性

